async (page) => {
  // Find and click the respawn button via DOM
  await page.evaluate(() => {
    // Look for button with RESPAWN text
    const buttons = document.querySelectorAll('button, input[type="button"], .button, [class*="respawn"]');
    for (const btn of buttons) {
      if (btn.textContent && btn.textContent.includes('RESPAWN')) {
        btn.click();
        return 'clicked respawn btn';
      }
    }
    // Try by specific class or id
    const anyBtn = document.querySelector('#respawn-button, .respawn, [id*="respawn"]');
    if (anyBtn) {
      anyBtn.click();
      return 'clicked by id/class';
    }
    return 'not found';
  });
  await page.waitForTimeout(3000);
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? JSON.stringify({ pos: gs.player_position, hp: gs.player_stats?.hp }) : '{}';
  });
  return state;
}

