async (page) => {
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  // Immediately look for a shop/store NPC
  const result = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const game = window.game;
    const entityMap = game.entities?.entities;

    // Find any store/shop/vendor NPCs
    const stores = [];
    for (const [id, entity] of Object.entries(entityMap || {})) {
      if (entity.name && (entity.name.includes('Shop') || entity.name.includes('Store') || 
          entity.name.includes('Vendor') || entity.name.includes('Merchant') ||
          entity.name.includes('Market') || entity.name.includes('Trade'))) {
        const px = game.player.x, py = game.player.y;
        const dist = Math.sqrt((entity.x-px)**2 + (entity.y-py)**2);
        stores.push({ name: entity.name, dist: Math.round(dist) });
      }
    }

    return JSON.stringify({ 
      pos: gs?.player_position,
      hp: gs?.player_stats?.hp,
      stores: stores.slice(0, 5)
    });
  });
  return result;
}

