async (page) => {
  // Helper: calc click coords from player+mob tile positions
  const calcClick = (px, py, mx, my) => ({
    x: 640 + (mx - px) * 48,
    y: 384 + (my - py) * 48
  });

  // Get state and attack nearest rat
  const getAndAttack = async () => {
    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      if (!gs) return null;
      const p = window.game.player;
      const skills = { str: p.skills?.[6]?.experience || 0, def: p.skills?.[7]?.experience || 0 };
      const rats = gs.nearby_entities ? gs.nearby_entities.filter(e => e.type === 3 && e.name === 'Rat').sort((a,b) => a.distance - b.distance) : [];
      return { pos: gs.player_position, hp: gs.player_stats, rats: rats.slice(0, 3), skills, target: gs.current_target };
    });
    return state;
  };

  // Attack Rat at (177,157), player at (176,157)
  let state = await getAndAttack();
  if (state && state.rats.length > 0) {
    const rat = state.rats[0];
    const c = calcClick(state.pos.x, state.pos.y, rat.x, rat.y);
    await page.evaluate(({x,y}) => {
