async (page) => {
  const calcClick = (px, py, mx, my) => ({
    x: 640 + (mx - px) * 48,
    y: 384 + (my - py) * 48
  });

  const getState = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return null;
    const p = window.game.player;
    return {
      pos: gs.player_position,
      hp: gs.player_stats.hp,
      max_hp: gs.player_stats.max_hp,
      level: gs.player_stats.level,
      rats: gs.nearby_entities ? gs.nearby_entities.filter(e => e.type === 3 && e.name === 'Rat' && e.distance <= 10) : [],
      skills: { str: p.skills?.[6]?.experience || 0, def: p.skills?.[7]?.experience || 0 },
      forester: gs.nearby_entities?.find(e => e.name === 'Forester')
    };
  });

  // Walk toward Forester while killing rats
  const foresterTile = { x: 216, y: 114 };

  for (let step = 0; step < 6; step++) {
    let s = await getState();
    if (!s) break;

    // If there's a rat nearby, attack it first
    if (s.rats.length > 0 && s.hp > s.max_hp * 0.5) {
      const rat = s.rats[0];
      const c = calcClick(s.pos.x, s.pos.y, rat.x, rat.y);
      await page.evaluate(({x,y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, c);
      await page.waitForTimeout(8000);
      s = await getState();
    }

    // Walk toward Forester
    if (s && Math.abs(s.pos.x - foresterTile.x) > 5 || Math.abs(s.pos.y - foresterTile.y) > 5) {
      const dx = Math.sign(foresterTile.x - s.pos.x);
      const dy = Math.sign(foresterTile.y - s.pos.y);
      // Walk: click in direction
      const cx = 640 + dx * 400; // strong directional click
      const cy = 384 + dy * 200;
      await page.evaluate(({x,y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, {x: Math.max(50, Math.min(1230, cx)), y: Math.max(50, Math.min(718, cy))});
      await page.waitForTimeout(4000);
    }

    if (s?.forester) break;
  }

  const final = await getState();
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: final?.pos, level: final?.level, skills: final?.skills, forester: final?.forester?.distance, hp: final?.hp + '/' + final?.max_hp });
}

