    }, {x:cx, y:cy});
  };

  const getState = async () => {
    const s = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    return JSON.parse(s);
  };

  let kills = 0;

  for (let i = 0; i < 50; i++) {
    const gs = await getState();

    if (gs.player_stats.hp === 0) {
