        setTimeout(() => document.getElementById('warp0').click(), 500);
      });
      await page.waitForTimeout(3000);
      await page.evaluate(() => window.game.player.setAttackStyle(1));
      continue;
    }

    const pos = gs.player_position;
    const hp = gs.player_stats.hp;
    const maxHp = gs.player_stats.max_hp;

    if (hp < maxHp * 0.45) {
      const food = gs.inventory?.find(item => item.edible);
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(1000);
      } else {
        await page.waitForTimeout(5000);
      }
      continue;
    }

    const mob = gs.nearby_entities?.find(e => 
      e.type === 3 && e.name === 'Batterfly' && e.hp > 0 && e.distance < 12
    ) || gs.nearby_entities?.find(e => 
      e.type === 3 && e.name === 'Rat' && e.hp > 0 && e.distance < 10
    );

    if (!mob) {
      await dismissAndClick(900, 500);
      await page.waitForTimeout(2000);
      continue;
    }

    const cx = 640 + (mob.x - pos.x) * 48;
    const cy = mob.y === pos.y ? 384 : 384 + (mob.y - pos.y) * 48;
    await dismissAndClick(cx, cy);
    await page.waitForTimeout(mob.name === 'Batterfly' ? 15000 : 9000);
    kills++;

    const strLevel = await page.evaluate(() => window.game.player.skills?.[6]?.level || 1);
    if (strLevel >= 10) break;
    if (kills % 5 === 0) {
      const strXP = await page.evaluate(() => window.game.player.skills?.[6]?.experience || 0);
      console.log(`Kill ${kills}: str=${strLevel}(${strXP}) hp=${gs.player_stats.hp}/${gs.player_stats.max_hp}`);
    }
  }

  const gs = await getState();
  const strLevel = await page.evaluate(() => window.game.player.skills?.[6]?.level || 1);
  const strXP = await page.evaluate(() => window.game.player.skills?.[6]?.experience || 0);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ kills, strLevel, strXP, hp: `${gs.player_stats.hp}/${gs.player_stats.max_hp}`, level: gs.player_stats.level, pos: gs.player_position });
}

