async (page) => {
  const dismissAndMove = async (cx, cy) => {
    await page.evaluate(() => {
      const r = document.getElementById('respawn');
      if (r && window.getComputedStyle(r).display === 'flex') { r.style.display='none'; r.click(); }
      const d = document.getElementById('death');
      if (d && window.getComputedStyle(d).display === 'flex') { d.click(); }
    });
    await page.evaluate(({x,y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x:cx, y:cy});
  };

  const getState = async () => {
    const s = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    return JSON.parse(s);
  };

  for (let step = 0; step < 12; step++) {
    const gs = await getState();
    const pos = gs.player_position;
    const hp = gs.player_stats.hp;
    const maxHp = gs.player_stats.max_hp;

    if (hp === 0) {
      await page.evaluate(() => { const d = document.getElementById('death'); if (d) d.click(); });
      await page.waitForTimeout(2000);
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 500); });
      await page.waitForTimeout(3000);
      return 'DIED';
    }
    if (hp < maxHp * 0.35) { await page.waitForTimeout(5000); continue; }

    const miner = gs.nearby_entities?.find(e => e.name === 'Miner');
    if (!miner) { await dismissAndMove(900, 700); await page.waitForTimeout(2500); continue; }

    if (miner.distance <= 3) {
      // Talk to Miner - click through dialogue and accept quest
      for (let i = 0; i < 8; i++) {
        const gs2 = await getState();
        const pos2 = gs2.player_position;
        const m = gs2.nearby_entities?.find(e => e.name === 'Miner');
        if (!m) break;
        const cx = 640 + (m.x - pos2.x) * 48;
        const cy = m.y === pos2.y ? 384 : 384 + (m.y - pos2.y) * 48;
        await dismissAndMove(cx, cy);
        await page.waitForTimeout(1200);
        await page.evaluate(() => {
          const btn = document.getElementById('quest-button');
          if (btn && window.getComputedStyle(btn).display === 'flex') btn.click();
        });
        await page.waitForTimeout(500);
        const gs3 = await getState();
        const mq = gs3.quests.find(q => q.key === 'minersquest');
        if (mq?.started) {
          await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
          return `Miner's Quest started! stage=${mq.stage}`;
        }
      }
      await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
      return `Talked to Miner`;
    }

    // Walk toward Miner
    const dx = miner.x - pos.x;
    const dy = miner.y - pos.y;
    const cx = Math.min(1260, Math.max(10, 640 + dx * 20));
    const cy = Math.min(700, Math.max(10, 384 + dy * 20));
    await dismissAndMove(cx, cy);
    await page.waitForTimeout(2500);
    console.log(`Step ${step}: pos=${JSON.stringify(pos)} minerDist=${miner.distance}`);
  }

  const gs = await getState();
  const miner = gs.nearby_entities?.find(e => e.name === 'Miner');
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: gs.player_position, minerDist: miner?.distance });
}

