async (page) => {
  const getState = () => page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, level: s.player_stats.level };
  });
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  await page.evaluate(() => window.game.player.setAttackStyle(1));
  let kills = 0;

  for (let i = 0; i < 15; i++) {
    const gs = await getState();
    if (gs.hp === 0) {
      await page.evaluate(() => { const d = document.getElementById('death'); if(d) d.click(); });
      await page.waitForTimeout(2000);
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 500); });
      await page.waitForTimeout(4000);
      await page.evaluate(() => window.game.player.setAttackStyle(1));
      break;
    }
    // Only fight if HP is decent
    if (gs.hp < gs.max_hp * 0.5) {
      await page.waitForTimeout(8000); // Wait for regen
      continue;
    }
    // Find a safe Rat to kill
    const rat = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s.nearby_entities?.find(e => e.name === 'Rat' && e.on_screen && e.distance < 12);
    });
    if (!rat) {
      await click(640, 600);
      await page.waitForTimeout(2000);
      continue;
    }
    const pos = await page.evaluate(() => window.__latestGameState?.player_position);
    const cx = 640 + (rat.x - pos.x) * 48;
    const cy = rat.y === pos.y ? 384 : 384 + (rat.y - pos.y) * 48;
    await click(Math.max(50, Math.min(1230, cx)), Math.max(50, Math.min(750, cy)));
    await page.waitForTimeout(5000);
    // Check for drops
    const drops = await page.evaluate(() => window.__latestGameState?.nearby_entities?.filter(e => e.type === 4 && e.on_screen).map(e => ({name: e.name, x: e.x, y: e.y})));
    const pos2 = await page.evaluate(() => window.__latestGameState?.player_position);
    for (const drop of (drops || [])) {
      const dcx = 640 + (drop.x - pos2.x) * 48;
      const dcy = drop.y === pos2.y ? 384 : 384 + (drop.y - pos2.y) * 48;
      await click(Math.max(50, Math.min(1230, dcx)), Math.max(50, Math.min(750, dcy)));
      await page.waitForTimeout(1000);
    }
    kills++;
  }

  const final = await getState();
  const inv = await page.evaluate(() => window.__latestGameState?.inventory?.map(i => ({key: i.key, name: i.name, count: i.count, edible: i.edible})));
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: final.pos, hp: final.hp, max_hp: final.max_hp, level: final.level, kills, inv });
}

async (page) => {
  const getState = () => page.evaluate(() => ({
    pos: window.__latestGameState?.player_position,
    hp: window.__latestGameState?.player_stats?.hp,
    max_hp: window.__latestGameState?.player_stats?.max_hp
  }));
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});
  const tryQuestBtn = () => page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn && window.getComputedStyle(btn).display === 'flex') { btn.click(); return 'clicked'; }
    return 'not visible';
  });

  await page.evaluate(() => window.game.player.setAttackStyle(1));

  // Navigate east along y≈173-178 toward Miner (323,178)
  for (let i = 0; i < 40; i++) {
    const gs = await getState();
    if (gs.hp === 0) {
      await page.evaluate(() => { const d = document.getElementById('death'); if(d) d.click(); });
      await page.waitForTimeout(2000);
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 500); });
      await page.waitForTimeout(4000);
      return 'died and warped';
    }
    if (gs.hp < 80) {
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 500); });
      await page.waitForTimeout(5000);
      return JSON.stringify({ result: 'warped low hp', pos: gs.pos });
    }
    const miner = await page.evaluate(() => window.__latestGameState?.nearby_entities?.find(e => e.name === 'Miner'));
    if (miner && miner.distance <= 4) break;
    if (miner) {
      const cx = 640 + (miner.x - gs.pos.x) * 48;
      const cy = miner.y === gs.pos.y ? 384 : 384 + (miner.y - gs.pos.y) * 48;
      await click(Math.max(50, Math.min(1230, cx)), Math.max(50, Math.min(750, cy)));
    } else {
      // Click east toward (323,178) — stay at y≈178
      const cx = 640 + (323 - gs.pos.x) * 48;
      const cy = 178 === gs.pos.y ? 384 : 384 + (178 - gs.pos.y) * 48;
      await click(Math.max(50, Math.min(1230, cx)), Math.max(50, Math.min(750, cy)));
    }
    await page.waitForTimeout(2500);
  }

  const final = await getState();
  const miner = await page.evaluate(() => window.__latestGameState?.nearby_entities?.find(e => e.name === 'Miner'));

  // If adjacent, start quest dialogue
  if (miner && miner.distance <= 4) {
    for (let i = 0; i < 8; i++) {
      const pos = await page.evaluate(() => window.__latestGameState?.player_position);
      const m = await page.evaluate(() => window.__latestGameState?.nearby_entities?.find(e => e.name === 'Miner'));
      if (!m) break;
      const cx = 640 + (m.x - pos.x) * 48;
      const cy = m.y === pos.y ? 384 : 384 + (m.y - pos.y) * 48;
      await click(Math.max(50, Math.min(1230, cx)), cy === 0 ? 384 : cy);
      await page.waitForTimeout(1200);
      await tryQuestBtn();
      const mq = await page.evaluate(() => window.__latestGameState?.quests?.find(q => q.key === 'minersquest'));
      if (mq?.started) break;
    }
  }

  const quests = await page.evaluate(() => window.__latestGameState?.quests?.filter(q => q.started && !q.finished).map(q => ({key: q.key, stage: q.stage})));
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: final.pos, hp: final.hp, minerDist: miner?.distance, quests });
}

