async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Navigate toward Miner at (323,178) from (245,149)
  // Need to go east ~78 tiles, south ~29 tiles
  // Be careful of unnamed mobs (Desert Scorpions)

  let lastPos = {x: 245, y: 149};
  for (let i = 0; i < 20; i++) {
    const pos = await page.evaluate(() => window.__latestGameState?.player_position);
    if (!pos) break;

    // Check HP
    const hp = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return { hp: gs.player_stats?.hp, max: gs.player_stats?.max_hp };
    });
    if (hp.hp < hp.max * 0.4) break; // retreat if low HP

    // Check if Miner visible and close
    const miner = await page.evaluate(() => 
      window.__latestGameState?.nearby_entities?.find(e => e.name === 'Miner')
    );
    if (miner && miner.distance <= 5) break;
    if (pos.x >= 320 && Math.abs(pos.y - 178) <= 5) break;

    // Navigate toward Miner: east-southeast
    // Miner is south-east of current position
    const dx = 323 - pos.x;
    const dy = 178 - pos.y;
    const angle = Math.atan2(dy, dx);
    // Canvas click: go toward right-bottom
    const cx = Math.min(1230, 640 + Math.cos(angle) * 500);
    const cy = Math.min(720, 384 + Math.sin(angle) * 500);

    await click(cx, cy);
    await page.waitForTimeout(2500);
    lastPos = pos;
  }

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {
      pos: gs.player_position,
      hp: gs.player_stats,
      miner: gs.nearby_entities?.find(e => e.name === 'Miner'),
      quest_npcs: gs.nearby_entities?.filter(e => e.quest_npc).map(e => ({name: e.name, x: e.x, y: e.y, dist: e.distance}))
    };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

