async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Set Hack attack style for strength XP
  await page.evaluate(() => window.game.player.setAttackStyle(1));

  // Fight the nearest Snek to clear path
  const mob = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const pos = gs.player_position;
    const sneks = gs.nearby_entities?.filter(e => e.type === 3 && e.name === 'Snek' && e.distance < 5);
    if (!sneks || sneks.length === 0) return null;
    sneks.sort((a, b) => a.distance - b.distance);
    const s = sneks[0];
    const cx = 640 + (s.x - pos.x) * 48;
    const cy = s.y === pos.y ? 384 : 384 + (s.y - pos.y) * 48;
    return { cx, cy, name: s.name };
  });

  if (mob) {
    await click(mob.cx, mob.cy);
    await page.waitForTimeout(6000); // wait for kill
  }

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos, hp, fought: mob?.name });
}

